ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?year WHERE {
  ?albums a :Album .
  ?songs a :Song .
  ?songs p:hasAlbums ?albums .
  ?albums p:Year ?year .
  ?songs p:Length ?length_o .
}
ORDER BY ASC(?length_o)
LIMIT 1 }
  component_2: { SELECT ?month WHERE {
  ?albums a :Album .
  ?songs a :Song .
  ?songs p:hasAlbums ?albums .
  ?albums p:Month ?month .
  ?songs p:Length ?length_o .
}
ORDER BY ASC(?length_o)
LIMIT 1 }
  full: { SELECT ?year ?month WHERE {
  ?albums a :Album .
  ?songs a :Song .
  ?songs p:hasAlbums ?albums .
  ?albums p:Year ?year .
  ?albums p:Month ?month .
  ?songs p:Length ?length_o .
}
ORDER BY ASC(?length_o)
LIMIT 1 }
}

PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?year ?month WHERE {
  ?albums a :Album .
  ?artists a :Artist .
  ?albums p:hasArtists ?artists .
  ?albums p:Year ?year .
  ?albums p:Month ?month .
  ?artists p:name ?name_f .
  FILTER(STR(?name_f) = "David Brown")
} }
  component: { SELECT ?month WHERE {
  ?albums a :Album .
  ?artists a :Artist .
  ?albums p:hasArtists ?artists .
  ?albums p:Month ?month .
  ?artists p:name ?name_f .
  FILTER(STR(?name_f) = "David Brown")
} }
  component_2: { SELECT ?year WHERE {
  ?albums a :Album .
  ?artists a :Artist .
  ?albums p:hasArtists ?artists .
  ?albums p:Year ?year .
  ?artists p:name ?name_f .
  FILTER(STR(?name_f) = "David Brown")
} }
}
